class Solution {
public:
    vector<int> maximumCount(vector<int>& nums, vector<vector<int>>& queries) {
        const int MAX = 100000;
        vector<bool> is_prime(MAX + 1, true);
        is_prime[0] = is_prime[1] = false;
        for (int i = 2; i * i <= MAX; ++i) {
            if (is_prime[i]) {
                for (int j = i * i; j <= MAX; j += i) {
                    is_prime[j] = false;
                }
            }
        }

        int n = nums.size();
        vector<int> res;

        vector<int> freq(MAX + 1, 0);
        int T = 0, S = 0;

        for (int num : nums) {
            if (is_prime[num]) {
                int old_count = freq[num];
                freq[num]++;
                int new_count = freq[num];
                if (old_count == 0) {
                    T++;
                }
                if (old_count == 1) {
                    if (new_count >= 2) {
                        S++;
                    }
                } else if (old_count >= 2) {
                    if (new_count < 2) {
                        S--;
                    }
                }
            }
        }

        for (auto& query : queries) {
            int idx = query[0];
            int val = query[1];
            int old_val = nums[idx];

            if (is_prime[old_val]) {
                int old_count = freq[old_val];
                if (old_count == 1) {
                    T--;
                } else if (old_count >= 2) {
                    S--;
                }
                freq[old_val]--;
                int new_count = freq[old_val];
                if (new_count == 1) {
                    T++;
                } else if (new_count >= 2) {
                    S++;
                }
            }

            nums[idx] = val;

            if (is_prime[val]) {
                int old_count = freq[val];
                if (old_count == 1) {
                    T--;
                } else if (old_count >= 2) {
                    S--;
                }
                freq[val]++;
                int new_count = freq[val];
                if (new_count == 1) {
                    T++;
                } else if (new_count >= 2) {
                    S++;
                }
            }

            res.push_back(T + S);
        }

        return res;
    }
};

